-- CHAY SOLE database schema-- Idempotent — safe to re-runcreate extension if not exists "uuid-ossp";-- Admin allowlistcreate table if not exists public.admins (    id uuid primary key default uuid_generate_v4(),    email text unique not null,    created_at timestamptz not null default now()  );-- Seed first admin (update email as needed)insert into public.admins (email) values ('beau@chay-sole.com') on conflict (email) do nothing;-- Creativescreate table if not exists public.creatives (    id uuid primary key default uuid_generate_v4(),    title text not null,    notes text,    status text not null default 'draft' check (status in ('draft','active','archived')),    asset_type text check (asset_type in ('image','video')),    asset_url text,    asset_path text,    thumb_url text,    created_at timestamptz not null default now(),    updated_at timestamptz not null default now(),    platforms text[] not null default '{}',    ad_copy text,    post_link text,    ad_code text,    carousel_images text[] not null default '{}',    is_top_performer boolean not null default false,    drop_tag text  );create index if not exists creatives_status_idx on public.creatives(status);
